try:
    await asyncio.wait_for(lock.acquire(), timeout=0.0)
    # got the lock immediately
    try:
        await do_work()
    finally:
        lock.release()
except asyncio.TimeoutError:
    # lock was not immediately available
    pass

try:
    await asyncio.wait_for(lock.acquire(), timeout=5.0)
except asyncio.TimeoutError:
    raise RuntimeError("Potential deadlock: could not acquire lock within 5 seconds")
